```json
{
  "global": "Navigate to an online car-selling service and complete the vehicle offer form with the specified car details—license plate, state, zip, mileage, condition, interior, color, and key count—then submit the contact email to receive a purchase offer.",
  "subtasks": [
    {
      "subtask": "Access the car selling platform and initiate a new sale listing",
      "atomics": [
        "Open the car-selling web application (e.g., 'Sell My Car' portal)",
        "Click the 'Get an Offer' or 'Sell My Car' entry button to start the form"
      ]
    },
    {
      "subtask": "Enter vehicle identification and location details",
      "atomics": [
        "Type license plate number 'YAW639' into the license plate field",
        "Select 'Louisiana' (LA) as the vehicle registration state",
        "Enter zip code '70726' into the zip/postal code field"
      ]
    },
    {
      "subtask": "Enter vehicle physical characteristics and condition",
      "atomics": [
        "Select or type 'Black' for the vehicle exterior color",
        "Select 'Leather' for the interior type",
        "Set defect/damage status to 'No Defect' or equivalent none option",
        "Set number of keys to '1' (single key)"
      ]
    },
    {
      "subtask": "Enter mileage reading",
      "atomics": [
        "Type '222900' into the mileage/odometer field"
      ]
    },
    {
      "subtask": "Provide contact email and submit the offer request",
      "atomics": [
        "Enter 'sellmycar@mail.com' into the email address field",
        "Click the 'Get Offer' or 'Submit' button to send the request"
      ]
    }
  ],
  "global_atomics": [
    "Verify a confirmation message appears indicating the offer will be sent to sellmycar@mail.com",
    "Cross-check all submitted values (plate YAW639, LA, 70726, 222900 mi, black, leather, no defect, 1 key) match the form before final submission"
  ],
  "gold_actions": {
    "global": "Fill and submit the 'Sell My Car' offer form on the target web portal with exact field values: plate=YAW639, state=Louisiana, zip=70726, color=Black, interior=Leather, defect=None, keys=1, mileage=222900, email=sellmycar@mail.com.",
    "subtasks": [
      {
        "subtask": "Navigate to the sell-my-car portal and open the offer intake form",
        "atomics": [
          "Load the car-selling service URL in the browser",
          "Click the primary CTA button (e.g., 'Get a Cash Offer' / 'Sell My Car Now') to open the multi-step form"
        ]
      },
      {
        "subtask": "Populate license plate, state, and zip code fields",
        "atomics": [
          "Input 'YAW639' in the license plate text input",
          "Select 'Louisiana' from the state dropdown (value 'LA')",
          "Input '70726' in the zip code text input"
        ]
      },
      {
        "subtask": "Set vehicle appearance and condition form fields",
        "atomics": [
          "Select 'Black' from the color picker or dropdown",
          "Select 'Leather' from the interior material dropdown or radio group",
          "Select 'No Defect' (or 'None') from the damage/defect selector",
          "Select or input '1' for number of keys"
        ]
      },
      {
        "subtask": "Enter 222900 in the odometer/mileage input field",
        "atomics": [
          "Click the mileage input field and type '222900'"
        ]
      },
      {
        "subtask": "Input the offer recipient email and trigger form submission",
        "atomics": [
          "Click the email field and type 'sellmycar@mail.com'",
          "Click the final 'Get My Offer' / 'Submit' button to dispatch the offer request"
        ]
      }
    ],
    "global_atomics": [
      "Assert that the post-submission page or modal displays a success message referencing sellmycar@mail.com as the offer destination",
      "Visually confirm the summary screen shows plate YAW639, mileage 222900, Louisiana / 70726, black, leather, no defect, 1 key before clicking submit"
    ]
  }
}
```
